"""Dashboard Web — NexusEngine Omega v3.0 | Autor: Emanuel Felipe"""
from fastapi import APIRouter
from fastapi.responses import HTMLResponse

ui_router = APIRouter(tags=["Dashboard"])

@ui_router.get("/dashboard", response_class=HTMLResponse, include_in_schema=False)
async def dashboard():
    return HTMLResponse(content=_HTML)

_HTML = '<!DOCTYPE html>\n<html lang="pt-BR">\n<head>\n<meta charset="UTF-8"/>\n<meta name="viewport" content="width=device-width,initial-scale=1"/>\n<title>NexusEngine</title>\n<link rel="preconnect" href="https://fonts.googleapis.com"/>\n<link href="https://fonts.googleapis.com/css2?family=Styrene+B:wght@400;500;700&family=Tiempos+Text:ital,wght@0,400;0,500;1,400&display=swap" rel="stylesheet"/>\n<style>\n/* ── Estilo Claude ────────────────────────────────────────────────── */\n:root {\n  --bg:     #1a1915;\n  --bg2:    #222118;\n  --bg3:    #2a2820;\n  --bg4:    #343128;\n  --bg5:    #3e3b30;\n  --ln:     #3a3828;\n  --ln2:    #4a4838;\n  --fg:     #f0ece0;\n  --fg2:    #b8b4a0;\n  --fg3:    #7a7868;\n  --fg4:    #5a5848;\n  --ac:     #d4a85a;\n  --ac2:    #c89440;\n  --ac3:    #e8c070;\n  --ok:     #6aab7a;\n  --err:    #c46060;\n  --info:   #6888c8;\n  --r:      10px;\n  --r2:     14px;\n  --shadow: 0 1px 3px rgba(0,0,0,.4), 0 0 0 1px rgba(255,255,255,.04);\n}\n*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\nhtml, body {\n  height: 100%;\n  background: var(--bg);\n  color: var(--fg);\n  font-family: \'Styrene B\', \'Segoe UI\', system-ui, sans-serif;\n  font-size: 14px;\n  line-height: 1.6;\n  -webkit-font-smoothing: antialiased;\n}\n::-webkit-scrollbar { width: 4px; height: 4px; }\n::-webkit-scrollbar-track { background: transparent; }\n::-webkit-scrollbar-thumb { background: var(--ln2); border-radius: 4px; }\na { color: var(--ac); text-decoration: none; }\na:hover { color: var(--ac3); }\n\n/* ── Layout ────────────────────────────────────────────────────────── */\n.shell { display: flex; height: 100vh; overflow: hidden; }\n.sidebar {\n  width: 256px; min-width: 256px;\n  background: var(--bg2);\n  border-right: 1px solid var(--ln);\n  display: flex; flex-direction: column;\n  overflow-y: auto;\n}\n.main { flex: 1; display: flex; flex-direction: column; overflow: hidden; }\n\n/* ── Sidebar ────────────────────────────────────────────────────────── */\n.sb-brand {\n  padding: 28px 24px 22px;\n  border-bottom: 1px solid var(--ln);\n}\n.sb-name {\n  font-size: 20px;\n  font-weight: 700;\n  color: var(--fg);\n  letter-spacing: -.3px;\n}\n.sb-tagline {\n  font-size: 11px;\n  color: var(--fg4);\n  margin-top: 3px;\n  letter-spacing: .3px;\n}\n\n.sb-status {\n  padding: 16px 24px;\n  border-bottom: 1px solid var(--ln);\n}\n.status-pill {\n  display: inline-flex; align-items: center; gap: 7px;\n  background: var(--bg3); border: 1px solid var(--ln2);\n  border-radius: 20px; padding: 5px 12px;\n  font-size: 12px; font-weight: 500;\n}\n.s-dot {\n  width: 7px; height: 7px; border-radius: 50%;\n  background: var(--err); flex-shrink: 0;\n  transition: background .3s, box-shadow .3s;\n}\n.s-dot.on {\n  background: var(--ok);\n  box-shadow: 0 0 0 3px rgba(106,171,122,.2);\n  animation: blink 2.4s ease-in-out infinite;\n}\n@keyframes blink { 0%,100%{opacity:1} 50%{opacity:.5} }\n#slbl { color: var(--fg2); transition: color .3s; }\n#slbl.on { color: var(--ok); }\n#sinfo { font-size: 11px; color: var(--fg4); margin-top: 8px; }\n\n.sb-section {\n  padding: 20px 24px 6px;\n  font-size: 10px; font-weight: 700;\n  letter-spacing: 1.2px; text-transform: uppercase;\n  color: var(--fg4);\n}\n.sb-item {\n  display: flex; align-items: center; gap: 10px;\n  padding: 9px 24px;\n  font-size: 13px; color: var(--fg3);\n  cursor: pointer;\n  border-left: 2px solid transparent;\n  transition: all .15s;\n}\n.sb-item:hover { background: var(--bg3); color: var(--fg2); }\n.sb-item.active { background: var(--bg3); color: var(--fg); border-left-color: var(--ac); }\n.sb-item .ic { font-size: 15px; width: 20px; text-align: center; opacity: .7; }\n.sb-item.active .ic { opacity: 1; }\n\n.sb-divider { height: 1px; background: var(--ln); margin: 8px 16px; }\n\n.sb-footer {\n  margin-top: auto;\n  padding: 16px 24px;\n  border-top: 1px solid var(--ln);\n  font-size: 11px; color: var(--fg4);\n}\n.sb-footer strong { color: var(--fg3); }\n\n/* ── Topbar ──────────────────────────────────────────────────────────── */\n.topbar {\n  background: var(--bg2);\n  border-bottom: 1px solid var(--ln);\n  padding: 0 28px;\n  height: 56px;\n  display: flex; align-items: center; gap: 10px;\n  flex-shrink: 0;\n}\n.topbar-title { font-size: 14px; font-weight: 600; flex: 1; color: var(--fg); }\n.topbar-sub { font-size: 11px; color: var(--fg4); }\n\n/* ── Buttons ──────────────────────────────────────────────────────────── */\n.btn {\n  display: inline-flex; align-items: center; gap: 6px;\n  border: none; border-radius: 8px;\n  font-family: inherit; font-size: 12px; font-weight: 600;\n  padding: 8px 16px; cursor: pointer;\n  transition: all .15s; letter-spacing: .1px;\n}\n.btn:active { transform: scale(.97); }\n.btn-primary {\n  background: var(--ac); color: #1a1710;\n  box-shadow: 0 1px 2px rgba(0,0,0,.3);\n}\n.btn-primary:hover { background: var(--ac3); }\n.btn-ghost {\n  background: var(--bg4); color: var(--fg2);\n  border: 1px solid var(--ln2);\n}\n.btn-ghost:hover { background: var(--bg5); color: var(--fg); border-color: var(--ln2); }\n.btn-ok { background: rgba(106,171,122,.15); color: var(--ok); border: 1px solid rgba(106,171,122,.3); }\n.btn-ok:hover { background: rgba(106,171,122,.25); }\n.btn-info { background: rgba(104,136,200,.15); color: var(--info); border: 1px solid rgba(104,136,200,.3); }\n.btn-info:hover { background: rgba(104,136,200,.25); }\n.btn-sm { padding: 5px 12px; font-size: 11px; }\n.btn-xs { padding: 3px 9px; font-size: 10px; }\n\n/* ── Panels ──────────────────────────────────────────────────────────── */\n.panels { flex: 1; overflow: hidden; }\n.panel { display: none; height: 100%; overflow-y: auto; padding: 28px; }\n.panel.active { display: block; }\n\n/* ── Cards ────────────────────────────────────────────────────────────── */\n.g4 { display: grid; grid-template-columns: repeat(4,1fr); gap: 10px; }\n.g3 { display: grid; grid-template-columns: repeat(3,1fr); gap: 10px; }\n.g6 { display: grid; grid-template-columns: repeat(6,1fr); gap: 8px; }\n.g2 { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }\n\n.card {\n  background: var(--bg3);\n  border: 1px solid var(--ln);\n  border-radius: var(--r2);\n  padding: 18px 20px;\n  transition: border-color .2s;\n}\n.card:hover { border-color: var(--ln2); }\n\n.mod-card .mc-icon { font-size: 22px; margin-bottom: 10px; }\n.mod-card .mc-name { font-size: 13px; font-weight: 700; color: var(--fg); }\n.mod-card .mc-desc { font-size: 11px; color: var(--fg4); margin-top: 3px; line-height: 1.4; }\n.mod-card .mc-tag {\n  display: inline-flex; align-items: center;\n  margin-top: 10px; padding: 2px 9px;\n  border-radius: 20px; font-size: 10px; font-weight: 600;\n  background: rgba(212,168,90,.12); color: var(--ac);\n  border: 1px solid rgba(212,168,90,.2);\n}\n\n.mcard {\n  background: var(--bg3); border: 1px solid var(--ln);\n  border-radius: var(--r); padding: 14px 16px;\n}\n.mcard-l { font-size: 10px; font-weight: 700; letter-spacing: .6px; text-transform: uppercase; color: var(--fg4); margin-bottom: 6px; }\n.mcard-v { font-size: 24px; font-weight: 700; color: var(--ac); line-height: 1; }\n.mcard-s { font-size: 10px; color: var(--fg4); margin-top: 4px; }\n\n.sect {\n  font-size: 10px; font-weight: 700;\n  letter-spacing: 1px; text-transform: uppercase;\n  color: var(--fg4); margin: 22px 0 12px;\n}\n.sect:first-child { margin-top: 0; }\n\nhr { border: none; border-top: 1px solid var(--ln); margin: 22px 0; }\n\n/* ── Tag chips ────────────────────────────────────────────────────────── */\n.chip {\n  display: inline-flex; align-items: center; gap: 4px;\n  padding: 2px 9px; border-radius: 20px;\n  font-size: 10px; font-weight: 600; letter-spacing: .3px;\n}\n.chip-gold  { background:rgba(212,168,90,.12); color:var(--ac);  border:1px solid rgba(212,168,90,.2); }\n.chip-ok    { background:rgba(106,171,122,.12); color:var(--ok); border:1px solid rgba(106,171,122,.2); }\n.chip-info  { background:rgba(104,136,200,.12); color:var(--info);border:1px solid rgba(104,136,200,.2); }\n.chip-err   { background:rgba(196,96,96,.12);   color:var(--err); border:1px solid rgba(196,96,96,.2); }\n\n/* ── Bar chart ────────────────────────────────────────────────────────── */\n.bar-wrap { background: var(--bg4); border-radius: 4px; height: 5px; margin-top: 6px; overflow: hidden; }\n.bar-fill { height: 100%; border-radius: 4px; background: linear-gradient(90deg, var(--ac2), var(--ac)); transition: width .6s ease; }\n\n/* ── Tester ────────────────────────────────────────────────────────────── */\n.tester { display: grid; grid-template-columns: 360px 1fr; gap: 16px; height: calc(100vh - 140px); }\n.tester-left { display: flex; flex-direction: column; gap: 12px; overflow-y: auto; padding-right: 4px; }\n.tester-right { display: flex; flex-direction: column; gap: 8px; }\n\nlabel.lbl {\n  display: block;\n  font-size: 10px; font-weight: 700;\n  letter-spacing: .6px; text-transform: uppercase;\n  color: var(--fg4); margin-bottom: 6px;\n}\nselect, textarea, input {\n  width: 100%;\n  background: var(--bg3);\n  border: 1px solid var(--ln);\n  border-radius: 9px;\n  color: var(--fg);\n  font-family: inherit; font-size: 12px;\n  padding: 9px 12px;\n  outline: none;\n  transition: border-color .15s;\n}\nselect:focus, textarea:focus, input:focus { border-color: var(--ac); }\nselect option { background: var(--bg3); }\ntextarea {\n  resize: vertical;\n  font-family: \'Menlo\', \'Consolas\', monospace;\n  font-size: 11px; line-height: 1.6;\n}\n\n.resp-hdr { display: flex; align-items: center; justify-content: space-between; flex-shrink: 0; }\n#resp-body {\n  flex: 1;\n  background: var(--bg3); border: 1px solid var(--ln);\n  border-radius: var(--r2); padding: 14px 16px;\n  font-family: \'Menlo\', \'Consolas\', monospace;\n  font-size: 11px; color: var(--fg); line-height: 1.6;\n  overflow-y: auto; white-space: pre-wrap; min-height: 200px;\n}\n\n/* ── Log ────────────────────────────────────────────────────────────────── */\n.logbox {\n  background: var(--bg3); border: 1px solid var(--ln);\n  border-radius: var(--r2);\n  height: calc(100vh - 180px);\n  overflow-y: auto; padding: 14px 16px;\n  font-family: \'Menlo\', \'Consolas\', monospace;\n  font-size: 11px; line-height: 1.8; color: var(--fg3);\n}\n.l-ok   { color: var(--ok); }\n.l-err  { color: var(--err); }\n.l-ac   { color: var(--ac); }\n.l-info { color: var(--info); }\n.l-dim  { color: var(--fg4); }\n\n/* ── About ────────────────────────────────────────────────────────────── */\n.about-wrap { max-width: 520px; margin: 40px auto; }\n.about-name { font-size: 32px; font-weight: 700; color: var(--fg); letter-spacing: -.5px; }\n.about-sub  { font-size: 14px; color: var(--fg3); margin-top: 6px; }\n.about-desc { font-size: 13px; color: var(--fg2); line-height: 1.7; margin: 20px 0; }\n.kv-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 8px; margin: 20px 0; }\n.kv { background: var(--bg3); border: 1px solid var(--ln); border-radius: var(--r); padding: 14px 16px; }\n.kv-k { font-size: 10px; font-weight: 700; letter-spacing: .6px; text-transform: uppercase; color: var(--fg4); }\n.kv-v { font-size: 13px; font-weight: 600; color: var(--fg); margin-top: 4px; }\n\n/* ── Spinner ────────────────────────────────────────────────────────────── */\n.spin {\n  display: inline-block; width: 12px; height: 12px;\n  border: 2px solid var(--ln2); border-top-color: var(--ac);\n  border-radius: 50%; animation: rot .65s linear infinite;\n}\n@keyframes rot { to { transform: rotate(360deg); } }\n\n/* ── Badge ─────────────────────────────────────────────────────────────── */\n.badge {\n  display: inline-flex; align-items: center; gap: 5px;\n  padding: 3px 10px; border-radius: 6px;\n  font-size: 11px; font-weight: 700;\n}\n.badge-ok  { background:rgba(106,171,122,.15); color:var(--ok);  border:1px solid rgba(106,171,122,.3); }\n.badge-err { background:rgba(196,96,96,.15);   color:var(--err); border:1px solid rgba(196,96,96,.3); }\n</style>\n</head>\n<body>\n<div class="shell">\n\n<!-- SIDEBAR -->\n<aside class="sidebar">\n  <div class="sb-brand">\n    <div class="sb-name">NexusEngine</div>\n    <div class="sb-tagline">Motor Computacional · v3.0.0</div>\n  </div>\n\n  <div class="sb-status">\n    <div class="status-pill">\n      <div class="s-dot" id="dot"></div>\n      <span id="slbl">Verificando...</span>\n    </div>\n    <div id="sinfo">Aguardando métricas</div>\n  </div>\n\n  <div class="sb-section">Navegação</div>\n  <div class="sb-item active" onclick="nav(\'dash\',this)">\n    <span class="ic">◈</span> Dashboard\n  </div>\n  <div class="sb-item" onclick="nav(\'test\',this)">\n    <span class="ic">⚡</span> Testar API\n  </div>\n  <div class="sb-item" onclick="nav(\'log\',this)">\n    <span class="ic">◎</span> Log\n  </div>\n  <div class="sb-item" onclick="nav(\'about\',this)">\n    <span class="ic">◇</span> Sobre\n  </div>\n\n  <div class="sb-divider"></div>\n  <div class="sb-section">Links</div>\n  <div class="sb-item" onclick="window.open(\'/docs\',\'_blank\')">\n    <span class="ic">↗</span> Swagger UI\n  </div>\n  <div class="sb-item" onclick="window.open(\'/redoc\',\'_blank\')">\n    <span class="ic">↗</span> ReDoc\n  </div>\n  <div class="sb-item" onclick="window.open(\'/metrics\',\'_blank\')">\n    <span class="ic">↗</span> Metrics JSON\n  </div>\n\n  <div class="sb-footer">\n    <strong>Emanuel Felipe</strong><br>\n    MIT License · 2026\n  </div>\n</aside>\n\n<!-- MAIN -->\n<div class="main">\n  <div class="topbar">\n    <div>\n      <div class="topbar-title">NexusEngine</div>\n    </div>\n    <button class="btn btn-ghost btn-sm" onclick="window.open(\'/docs\',\'_blank\')">Swagger</button>\n    <button class="btn btn-ghost btn-sm" onclick="qtest(\'health\')">Health</button>\n    <button class="btn btn-primary btn-sm" onclick="qtest(\'stress\')">Stress Test</button>\n  </div>\n\n  <div class="panels">\n\n    <!-- DASHBOARD -->\n    <div class="panel active" id="p-dash">\n      <div class="sect">Módulos</div>\n      <div class="g4">\n        <div class="card mod-card">\n          <div class="mc-icon">⊕</div>\n          <div class="mc-name">Binary</div>\n          <div class="mc-desc">14 operações bit a bit em 64 bits</div>\n          <div class="mc-tag">XOR · AND · OR · NOT · NAND · ROL</div>\n        </div>\n        <div class="card mod-card">\n          <div class="mc-icon">⊞</div>\n          <div class="mc-name">Matrix</div>\n          <div class="mc-desc">10 tipos de matrizes com análise NumPy</div>\n          <div class="mc-tag">det · rank · norm · solve · multiply</div>\n        </div>\n        <div class="card mod-card">\n          <div class="mc-icon">ψ</div>\n          <div class="mc-name">Quantum</div>\n          <div class="mc-desc">Simulador de vetor de estado completo</div>\n          <div class="mc-tag">12 portas · entropia · Bell · GHZ</div>\n        </div>\n        <div class="card mod-card">\n          <div class="mc-icon">#</div>\n          <div class="mc-name">Hash</div>\n          <div class="mc-desc">10 algoritmos criptográficos + HMAC</div>\n          <div class="mc-tag">SHA · Blake2 · MD5 · HMAC · verify</div>\n        </div>\n      </div>\n\n      <div class="g4" style="margin-top:10px">\n        <div class="card mod-card">\n          <div class="mc-icon">↕</div>\n          <div class="mc-name">Sort</div>\n          <div class="mc-desc">8 algoritmos com telemetria e benchmark</div>\n          <div class="mc-tag">quick · merge · heap · shell · bubble</div>\n        </div>\n        <div class="card mod-card">\n          <div class="mc-icon">∞</div>\n          <div class="mc-name">Prime</div>\n          <div class="mc-desc">Crivos, fatoração e Goldbach</div>\n          <div class="mc-tag">sieve · factorize · goldbach · nth</div>\n        </div>\n        <div class="card mod-card">\n          <div class="mc-icon">φ</div>\n          <div class="mc-name">Sequences</div>\n          <div class="mc-desc">Sequências matemáticas clássicas</div>\n          <div class="mc-tag">Fibonacci · Collatz · Pascal · Lucas</div>\n        </div>\n        <div class="card mod-card">\n          <div class="mc-icon">∑</div>\n          <div class="mc-name">Statistics</div>\n          <div class="mc-desc">Análise estatística completa de datasets</div>\n          <div class="mc-tag">média · percentis · correlação · hist</div>\n        </div>\n      </div>\n\n      <div class="sect">Métricas ao vivo</div>\n      <div class="g6">\n        <div class="mcard">\n          <div class="mcard-l">Operações</div>\n          <div class="mcard-v" id="m-ops">0</div>\n          <div class="mcard-s">total processadas</div>\n        </div>\n        <div class="mcard">\n          <div class="mcard-l">Throughput</div>\n          <div class="mcard-v" id="m-thr">—</div>\n          <div class="mcard-s">operações / segundo</div>\n        </div>\n        <div class="mcard">\n          <div class="mcard-l">Latência p99</div>\n          <div class="mcard-v" id="m-p99">—</div>\n          <div class="mcard-s">microsegundos</div>\n        </div>\n        <div class="mcard">\n          <div class="mcard-l">CPU</div>\n          <div class="mcard-v" id="m-cpu">—</div>\n          <div class="mcard-s">uso do processo</div>\n        </div>\n        <div class="mcard">\n          <div class="mcard-l">Memória</div>\n          <div class="mcard-v" id="m-mem">—</div>\n          <div class="mcard-s">megabytes (RSS)</div>\n        </div>\n        <div class="mcard">\n          <div class="mcard-l">Uptime</div>\n          <div class="mcard-v" id="m-up">0</div>\n          <div class="mcard-s">segundos</div>\n        </div>\n      </div>\n\n      <div id="mod-usage"></div>\n\n      <hr/>\n\n      <div class="sect">Ações rápidas</div>\n      <div style="display:flex;gap:8px;flex-wrap:wrap">\n        <button class="btn btn-ghost" onclick="window.open(\'/docs\',\'_blank\')">↗ Swagger UI</button>\n        <button class="btn btn-ghost" onclick="window.open(\'/redoc\',\'_blank\')">↗ ReDoc</button>\n        <button class="btn btn-ok" onclick="qtest(\'health\')">Health Check</button>\n        <button class="btn btn-primary" onclick="qtest(\'stress\')">Stress Test</button>\n        <button class="btn btn-info" onclick="qtest(\'quantum\')">Bell State</button>\n        <button class="btn btn-info" onclick="qtest(\'sort\')">Sort Benchmark</button>\n        <button class="btn btn-ghost" onclick="qtest(\'metrics\')">Ver métricas</button>\n      </div>\n    </div>\n\n    <!-- TESTER -->\n    <div class="panel" id="p-test">\n      <div class="tester">\n        <div class="tester-left">\n          <div>\n            <label class="lbl">Endpoint</label>\n            <select id="ep" onchange="onEp()">\n              <optgroup label="Health">\n                <option value="GET|/health|">GET /health</option>\n                <option value="GET|/metrics|">GET /metrics</option>\n                <option value="GET|/ping|">GET /ping</option>\n                <option value="GET|/engine/status|">GET /engine/status</option>\n              </optgroup>\n              <optgroup label="Engine">\n                <option value=\'POST|/engine/start|{"threads":4}\'>POST /engine/start</option>\n                <option value=\'POST|/engine/stop|{}\'>POST /engine/stop</option>\n              </optgroup>\n              <optgroup label="⊕ Binary">\n                <option value=\'POST|/compute/binary|{"operation":"xor","value_a":255,"value_b":170}\'>binary — XOR</option>\n                <option value=\'POST|/compute/binary|{"operation":"and","value_a":255,"value_b":170}\'>binary — AND</option>\n                <option value=\'POST|/compute/binary|{"operation":"not","value_a":255}\'>binary — NOT</option>\n                <option value=\'POST|/compute/binary|{"operation":"nand","value_a":255,"value_b":170}\'>binary — NAND</option>\n                <option value=\'POST|/compute/binary|{"operation":"shl","value_a":1,"value_b":8}\'>binary — shift left</option>\n                <option value=\'POST|/compute/binary|{"operation":"rol","value_a":1,"value_b":4}\'>binary — rotate left</option>\n                <option value=\'POST|/compute/binary|{"operation":"popcount","value_a":255}\'>binary — popcount</option>\n                <option value=\'POST|/compute/binary|{"operation":"reverse_bits","value_a":255}\'>binary — reverse bits</option>\n              </optgroup>\n              <optgroup label="⊞ Matrix">\n                <option value=\'POST|/compute/matrix|{"operation":"identity","rows":4,"cols":4}\'>matrix — identity 4×4</option>\n                <option value=\'POST|/compute/matrix|{"operation":"random_normal","rows":5,"cols":5}\'>matrix — random 5×5</option>\n                <option value=\'POST|/compute/matrix|{"operation":"hilbert","rows":5,"cols":5}\'>matrix — hilbert 5×5</option>\n                <option value=\'POST|/compute/matrix|{"operation":"magic","rows":5,"cols":5}\'>matrix — magic 5×5</option>\n                <option value=\'POST|/compute/matrix/multiply|{"a":[[1,2],[3,4]],"b":[[5,6],[7,8]]}\'>matrix — multiply A×B</option>\n                <option value=\'POST|/compute/matrix/solve|{"a":[[2,1],[5,7]],"b":[11,13]}\'>matrix — solve Ax=b</option>\n              </optgroup>\n              <optgroup label="ψ Quantum">\n                <option value=\'POST|/compute/quantum|{"qubits":4,"operation":"superposition"}\'>quantum — superposition 4q</option>\n                <option value=\'POST|/compute/quantum|{"qubits":2,"operation":"bell"}\'>quantum — Bell state 2q</option>\n                <option value=\'POST|/compute/quantum|{"qubits":3,"operation":"ghz"}\'>quantum — GHZ state 3q</option>\n                <option value=\'POST|/compute/quantum|{"qubits":2,"operation":"ground","gates":[{"gate":"H","qubit":0},{"gate":"CNOT","qubit":0,"target":1}]}\'>quantum — H + CNOT</option>\n              </optgroup>\n              <optgroup label="# Hash">\n                <option value=\'POST|/hash|{"data":"Emanuel Felipe","algorithm":"sha256"}\'>hash — sha256</option>\n                <option value=\'POST|/hash|{"data":"NexusEngine","algorithm":"blake2b"}\'>hash — blake2b</option>\n                <option value=\'POST|/hash/all|{"data":"NexusEngine","algorithm":"sha256"}\'>hash — todos os algoritmos</option>\n                <option value=\'POST|/hash/hmac|{"key":"secret","data":"mensagem","algorithm":"sha256"}\'>hash — HMAC</option>\n              </optgroup>\n              <optgroup label="↕ Sort">\n                <option value=\'POST|/compute/sort|{"data":[64,34,25,12,22,11,90],"algorithm":"quick"}\'>sort — quicksort</option>\n                <option value=\'POST|/compute/sort|{"data":[64,34,25,12,22,11,90],"algorithm":"merge"}\'>sort — mergesort</option>\n                <option value=\'POST|/compute/sort/benchmark|{"data":[64,34,25,12,22,11,90,55,43,17]}\'>sort — benchmark todos</option>\n              </optgroup>\n              <optgroup label="∞ Prime">\n                <option value=\'POST|/compute/prime|{"operation":"is_prime","n":97}\'>prime — is_prime(97)</option>\n                <option value=\'POST|/compute/prime|{"operation":"sieve","n":1,"limit":100}\'>prime — sieve até 100</option>\n                <option value=\'POST|/compute/prime|{"operation":"factorize","n":360}\'>prime — factorize(360)</option>\n                <option value=\'POST|/compute/prime|{"operation":"goldbach","n":28}\'>prime — goldbach(28)</option>\n              </optgroup>\n              <optgroup label="φ Sequences">\n                <option value=\'POST|/compute/sequence|{"operation":"fibonacci","n":20}\'>sequence — fibonacci(20)</option>\n                <option value=\'POST|/compute/sequence|{"operation":"collatz","n":27}\'>sequence — collatz(27)</option>\n                <option value=\'POST|/compute/sequence|{"operation":"pascal","n":8}\'>sequence — pascal 8 linhas</option>\n              </optgroup>\n              <optgroup label="∑ Statistics">\n                <option value=\'POST|/compute/stats|{"data":[2,4,4,4,5,5,7,9]}\'>stats — analyze</option>\n                <option value=\'POST|/compute/stats/correlation|{"x":[1,2,3,4,5],"y":[2,4,5,4,5]}\'>stats — correlation</option>\n                <option value=\'POST|/compute/stats/histogram|{"data":[1,2,2,3,3,3,4,4,5],"bins":5}\'>stats — histogram</option>\n              </optgroup>\n              <optgroup label="📊 Metrics">\n                <option value=\'POST|/metrics/stress|{"threads":4,"operations_per_thread":5000}\'>metrics — stress test</option>\n              </optgroup>\n            </select>\n          </div>\n\n          <div>\n            <label class="lbl">Body JSON</label>\n            <textarea id="body" rows="11" spellcheck="false"></textarea>\n          </div>\n\n          <button class="btn btn-primary" id="btn-send" onclick="send()" style="width:100%">\n            Enviar request\n          </button>\n          <button class="btn btn-ghost btn-sm" onclick="clearResp()" style="width:100%">\n            Limpar resposta\n          </button>\n        </div>\n\n        <div class="tester-right">\n          <div class="resp-hdr">\n            <label class="lbl" style="margin:0">Resposta</label>\n            <div style="display:flex;align-items:center;gap:8px">\n              <span id="resp-ms" style="font-size:11px;color:var(--fg4)"></span>\n              <span class="badge" id="resp-code"></span>\n            </div>\n          </div>\n          <div id="resp-body">Selecione um endpoint acima e clique em Enviar request.</div>\n        </div>\n      </div>\n    </div>\n\n    <!-- LOG -->\n    <div class="panel" id="p-log">\n      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:16px">\n        <div style="font-size:15px;font-weight:700">Log de requests</div>\n        <button class="btn btn-ghost btn-sm" onclick="clearLog()">Limpar</button>\n      </div>\n      <div class="logbox" id="logbox">\n        <span class="l-dim">Aguardando requests...</span>\n      </div>\n    </div>\n\n    <!-- ABOUT -->\n    <div class="panel" id="p-about">\n      <div class="about-wrap">\n        <div class="about-name">NexusEngine</div>\n        <div class="about-sub">Motor Computacional de Alta Performance · v3.0.0</div>\n        <div class="about-desc">\n          API REST de computação científica e criptográfica com 8 engines independentes.\n          Construída com FastAPI e NumPy, sem dependência de C++ ou Cython.\n          Inclui simulação quântica com vetor de estado completo, 8 algoritmos de ordenação\n          com telemetria, análise estatística e muito mais.\n        </div>\n\n        <div class="kv-grid">\n          <div class="kv"><div class="kv-k">Autor</div><div class="kv-v">Emanuel Felipe</div></div>\n          <div class="kv"><div class="kv-k">GitHub</div><div class="kv-v">@onerddev</div></div>\n          <div class="kv"><div class="kv-k">Licença</div><div class="kv-v">MIT</div></div>\n          <div class="kv"><div class="kv-k">Versão</div><div class="kv-v">3.0.0</div></div>\n          <div class="kv"><div class="kv-k">Framework</div><div class="kv-v">FastAPI + NumPy</div></div>\n          <div class="kv"><div class="kv-k">Engines</div><div class="kv-v">8 módulos</div></div>\n        </div>\n\n        <div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:8px">\n          <button class="btn btn-ghost" onclick="window.open(\'https://github.com/onerddev\',\'_blank\')">GitHub</button>\n          <button class="btn btn-info" onclick="window.open(\'/docs\',\'_blank\')">Swagger UI</button>\n          <button class="btn btn-ghost" onclick="window.open(\'/redoc\',\'_blank\')">ReDoc</button>\n        </div>\n\n        <hr/>\n        <div style="font-size:12px;color:var(--fg4)">\n          Desenvolvido por <strong style="color:var(--fg3)">Emanuel Felipe</strong>\n        </div>\n      </div>\n    </div>\n\n  </div>\n</div><!-- /main -->\n</div><!-- /shell -->\n\n<script>\n// ── Nav ────────────────────────────────────────────────────────────\nfunction nav(id, el) {\n  document.querySelectorAll(\'.sb-item\').forEach(i => i.classList.remove(\'active\'));\n  document.querySelectorAll(\'.panel\').forEach(p => p.classList.remove(\'active\'));\n  el.classList.add(\'active\');\n  document.getElementById(\'p-\' + id).classList.add(\'active\');\n}\n\n// ── Endpoint picker ────────────────────────────────────────────────\nfunction onEp() {\n  const [m, p, b] = document.getElementById(\'ep\').value.split(\'|\');\n  const ta = document.getElementById(\'body\');\n  try {\n    ta.value = (b && b !== \'{}\') ? JSON.stringify(JSON.parse(b), null, 2) : \'\';\n  } catch { ta.value = b || \'\'; }\n}\nonEp();\n\n// ── Send ────────────────────────────────────────────────────────────\nasync function send() {\n  const [method, path] = document.getElementById(\'ep\').value.split(\'|\');\n  const raw = document.getElementById(\'body\').value.trim();\n  const btn = document.getElementById(\'btn-send\');\n  btn.innerHTML = \'<span class="spin"></span> Enviando...\';\n  btn.disabled = true;\n\n  const t0 = performance.now();\n  try {\n    const opts = { method, headers: {} };\n    if (method === \'POST\') {\n      opts.headers[\'Content-Type\'] = \'application/json\';\n      opts.body = raw || \'{}\';\n    }\n    const r   = await fetch(path, opts);\n    const ms  = (performance.now() - t0).toFixed(0);\n    const txt = await r.text();\n    let pretty;\n    try { pretty = JSON.stringify(JSON.parse(txt), null, 2); }\n    catch { pretty = txt; }\n\n    document.getElementById(\'resp-body\').textContent = pretty;\n    document.getElementById(\'resp-ms\').textContent   = ms + \' ms\';\n    const badge = document.getElementById(\'resp-code\');\n    badge.textContent = \'HTTP \' + r.status;\n    badge.className   = \'badge \' + (r.ok ? \'badge-ok\' : \'badge-err\');\n    log(method + \' \' + path + \' → \' + r.status + \' (\' + ms + \'ms)\', r.ok ? \'l-ok\' : \'l-err\');\n  } catch(e) {\n    document.getElementById(\'resp-body\').textContent = \'Erro: \' + e.message;\n    document.getElementById(\'resp-code\').textContent = \'Erro\';\n    document.getElementById(\'resp-code\').className   = \'badge badge-err\';\n    log(\'Erro de conexão: \' + e.message, \'l-err\');\n  }\n\n  btn.innerHTML = \'Enviar request\';\n  btn.disabled  = false;\n}\n\nfunction clearResp() {\n  document.getElementById(\'resp-body\').textContent = \'Selecione um endpoint acima e clique em Enviar request.\';\n  document.getElementById(\'resp-code\').textContent = \'\';\n  document.getElementById(\'resp-ms\').textContent   = \'\';\n}\n\n// ── Quick tests ─────────────────────────────────────────────────────\nconst QUICK = {\n  health:  [\'GET\',  \'/health\',  \'\'],\n  metrics: [\'GET\',  \'/metrics\', \'\'],\n  stress:  [\'POST\', \'/metrics/stress\', \'{"threads":4,"operations_per_thread":5000}\'],\n  quantum: [\'POST\', \'/compute/quantum\', \'{"qubits":2,"operation":"bell"}\'],\n  sort:    [\'POST\', \'/compute/sort/benchmark\', \'{"data":[64,34,25,12,22,11,90,55,43,17,3]}\'],\n};\n\nasync function qtest(key) {\n  document.querySelectorAll(\'.sb-item\')[1].click();\n  const [m, p, b] = QUICK[key];\n  document.getElementById(\'body\').value = b ? JSON.stringify(JSON.parse(b), null, 2) : \'\';\n  await new Promise(r => setTimeout(r, 60));\n\n  const btn = document.getElementById(\'btn-send\');\n  btn.innerHTML = \'<span class="spin"></span> Enviando...\';\n  btn.disabled  = true;\n  const t0 = performance.now();\n  try {\n    const opts = { method: m, headers: {} };\n    if (m === \'POST\') { opts.headers[\'Content-Type\'] = \'application/json\'; opts.body = b || \'{}\'; }\n    const r   = await fetch(p, opts);\n    const ms  = (performance.now() - t0).toFixed(0);\n    const txt = await r.text();\n    let pretty;\n    try { pretty = JSON.stringify(JSON.parse(txt), null, 2); } catch { pretty = txt; }\n    document.getElementById(\'resp-body\').textContent = pretty;\n    document.getElementById(\'resp-ms\').textContent   = ms + \' ms\';\n    const badge = document.getElementById(\'resp-code\');\n    badge.textContent = \'HTTP \' + r.status;\n    badge.className   = \'badge \' + (r.ok ? \'badge-ok\' : \'badge-err\');\n    log(m + \' \' + p + \' → \' + r.status + \' (\' + ms + \'ms)\', r.ok ? \'l-ok\' : \'l-err\');\n  } catch(e) { log(\'Erro: \' + e.message, \'l-err\'); }\n  btn.innerHTML = \'Enviar request\';\n  btn.disabled  = false;\n}\n\n// ── Log ─────────────────────────────────────────────────────────────\nfunction log(msg, cls) {\n  const box = document.getElementById(\'logbox\');\n  const div = document.createElement(\'div\');\n  const ts  = new Date().toLocaleTimeString(\'pt-BR\');\n  div.innerHTML = \'<span class="l-dim">[\' + ts + \']</span> <span class="\' + (cls||\'\') + \'">\' + msg + \'</span>\';\n  box.appendChild(div);\n  box.scrollTop = box.scrollHeight;\n}\nfunction clearLog() { document.getElementById(\'logbox\').innerHTML = \'\'; }\n\n// ── Metrics polling ──────────────────────────────────────────────────\nasync function poll() {\n  try {\n    const r = await fetch(\'/metrics\');\n    if (!r.ok) throw 0;\n    const d   = await r.json();\n    const lat = d.latency_us || {};\n\n    document.getElementById(\'m-ops\').textContent = d.total_operations;\n    document.getElementById(\'m-thr\').textContent = d.throughput_ops_sec.toFixed(1);\n    document.getElementById(\'m-p99\').textContent = lat.p99 ? lat.p99.toFixed(1) + \' µs\' : \'—\';\n    document.getElementById(\'m-cpu\').textContent = d.cpu_percent.toFixed(1) + \'%\';\n    document.getElementById(\'m-mem\').textContent = (d.memory_bytes / 1024 / 1024).toFixed(0) + \' MB\';\n    document.getElementById(\'m-up\').textContent  = d.uptime_seconds + \'s\';\n    document.getElementById(\'sinfo\').textContent = \'Uptime: \' + d.uptime_seconds + \'s  ·  \' + d.total_operations + \' ops\';\n\n    document.getElementById(\'dot\').classList.add(\'on\');\n    document.getElementById(\'slbl\').classList.add(\'on\');\n    document.getElementById(\'slbl\').textContent = \'Online\';\n\n    // Barras por módulo\n    const bm = d.by_module || {};\n    const total = d.total_operations || 1;\n    const wrap = document.getElementById(\'mod-usage\');\n    if (Object.keys(bm).length) {\n      wrap.innerHTML = \'<div class="sect">Uso por módulo</div><div class="g4">\';\n      const g = wrap.querySelector(\'.g4\') || wrap;\n      wrap.innerHTML = \'<div class="sect">Uso por módulo</div>\';\n      const grid = document.createElement(\'div\');\n      grid.className = \'g4\';\n      for (const [mod, cnt] of Object.entries(bm)) {\n        const pct = Math.min(100, Math.round(cnt / total * 100));\n        const el  = document.createElement(\'div\');\n        el.style.cssText = \'background:var(--bg3);border:1px solid var(--ln);border-radius:var(--r);padding:12px 14px\';\n        el.innerHTML =\n          \'<div style="display:flex;justify-content:space-between;font-size:11px;margin-bottom:4px">\' +\n          \'<span style="font-weight:600;color:var(--fg2)">\' + mod + \'</span>\' +\n          \'<span style="color:var(--fg4)">\' + cnt + \' (\' + pct + \'%)</span></div>\' +\n          \'<div class="bar-wrap"><div class="bar-fill" style="width:\' + pct + \'%"></div></div>\';\n        grid.appendChild(el);\n      }\n      wrap.appendChild(grid);\n    }\n  } catch {\n    document.getElementById(\'dot\').classList.remove(\'on\');\n    document.getElementById(\'slbl\').classList.remove(\'on\');\n    document.getElementById(\'slbl\').textContent = \'Offline\';\n    document.getElementById(\'sinfo\').textContent = \'Servidor não responde\';\n  }\n}\n\nsetInterval(poll, 2500);\npoll();\nlog(\'NexusEngine Omega v3.0 · Dashboard carregado\', \'l-ac\');\nlog(\'Swagger: /docs  ·  ReDoc: /redoc  ·  Health: /health\', \'l-info\');\n</script>\n</body>\n</html>'
